// Process both Nurture Leads and Closed Lost Opportunities
// Determine alert window: Personal = 30 days, Commercial = 60 days before X-Date

const today = $today;
const results = [];

// Process Leads from input 0
const leads = $('Fetch Nurture Leads with X-Date').all();
for (const lead of leads) {
  const data = lead.json.list || [lead.json];
  for (const item of (Array.isArray(data) ? data : [])) {
    if (!item.xDate) continue;
    const xDate = DateTime.fromISO(item.xDate);
    const lob = (item.insuranceInterest || '').toLowerCase();
    const isCommercial = lob.includes('commercial') || lob.includes('workers') || lob.includes('general') || lob.includes('bop') || lob.includes('umbrella') || lob.includes('group');
    const alertDays = isCommercial ? 60 : 30;
    const alertDate = xDate.minus({ days: alertDays });

    if (today >= alertDate && today <= xDate) {
      results.push({
        json: {
          source: 'Lead',
          sourceId: item.id,
          name: item.name,
          xDate: item.xDate,
          lineOfBusiness: item.insuranceInterest,
          alertDays: alertDays,
          daysUntilXDate: Math.ceil(xDate.diff(today, 'days').days),
          assignedUserId: item.assignedUserId,
          accountId: item.accountId,
          contactId: item.contactId,
          estimatedPremium: item.estimatedPremium,
          action: 'Create Opportunity from Nurture Lead'
        }
      });
    }
  }
}

// Process Closed Lost Opps from input 1
const opps = $('Fetch Closed Lost Opps with X-Date').all();
for (const opp of opps) {
  const data = opp.json.list || [opp.json];
  for (const item of (Array.isArray(data) ? data : [])) {
    if (!item.closeDate) continue;
    const xDate = DateTime.fromISO(item.closeDate);
    const lob = (item.lineOfBusiness || '').toLowerCase();
    const isCommercial = lob.includes('commercial') || lob.includes('workers') || lob.includes('general') || lob.includes('bop') || lob.includes('umbrella') || lob.includes('group');
    const alertDays = isCommercial ? 60 : 30;
    const alertDate = xDate.minus({ days: alertDays });

    if (today >= alertDate && today <= xDate) {
      results.push({
        json: {
          source: 'Opportunity',
          sourceId: item.id,
          name: item.name || item.accountName,
          xDate: item.closeDate,
          lineOfBusiness: item.lineOfBusiness,
          alertDays: alertDays,
          daysUntilXDate: Math.ceil(xDate.diff(today, 'days').days),
          assignedUserId: item.assignedUserId,
          accountId: item.accountId,
          action: 'Re-open Opportunity from Closed Lost'
        }
      });
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];
